$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-evidence-'+[guid]::NewGuid().ToString('N'));try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$output=Join-Path $sandbox 'evidence.json';& (Join-Path $root 'scripts\export-ueef-evidence.ps1') -RepositoryPath $root -OutputPath $output|Out-Null;$r=Get-Content $output -Raw|ConvertFrom-Json;if($r.schemaVersion -ne 1 -or !$r.provenance.runtimeVersion){throw 'Evidence export contract failed.'};Write-Host 'Evidence export tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
